use std::fs;

fn main() {
    // Write a temp file then read it back
    fs::write("/tmp/hello.txt", "Hello, file!").unwrap();
    let contents = fs::read_to_string("/tmp/hello.txt").unwrap();
    println!("{}", contents);
}

use std::fs;

fn main() {
    let data = "line 1\nline 2\nline 3\n";
    fs::write("/tmp/data.txt", data).unwrap();
    println!("written");
    let back = fs::read_to_string("/tmp/data.txt").unwrap();
    print!("{}", back);
}

use std::fs;

fn read_or_default(path: &str, default: &str) -> String {
    match fs::read_to_string(path) {
        Ok(content) => content,
        Err(_)      => String::from(default),
    }
}

fn main() {
    let content = read_or_default("/tmp/exists.txt", "(file not found)");
    println!("{}", content.trim());
}

use std::fs::OpenOptions;
use std::io::Write;

fn main() {
    let mut f = OpenOptions::new()
        .create(true)
        .append(true)
        .open("/tmp/log.txt")
        .unwrap();
    writeln!(f, "log entry 1").unwrap();
    writeln!(f, "log entry 2").unwrap();
    let content = std::fs::read_to_string("/tmp/log.txt").unwrap();
    print!("{}", content);
}

use std::fs::File;
use std::io::{BufRead, BufReader};

fn main() {
    std::fs::write("/tmp/lines.txt", "apple\nbanana\ncherry\n").unwrap();
    let file = File::open("/tmp/lines.txt").unwrap();
    let reader = BufReader::new(file);
    for (i, line) in reader.lines().enumerate() {
        println!("{}: {}", i + 1, line.unwrap());
    }
}

use std::path::{Path, PathBuf};

fn main() {
    let p = Path::new("/tmp/hello.txt");
    println!("exists: {}", p.exists());
    println!("extension: {:?}", p.extension());
    println!("file name: {:?}", p.file_name());

    let mut pb = PathBuf::from("/tmp");
    pb.push("subdir");
    pb.push("file.rs");
    println!("path: {}", pb.display());
}

use std::fs;

fn main() {
    fs::write("/tmp/bytes.bin", &[72u8, 101, 108, 108, 111]).unwrap();
    let bytes = fs::read("/tmp/bytes.bin").unwrap();
    println!("bytes: {:?}", bytes);
    println!("as string: {}", String::from_utf8(bytes).unwrap());
}

use std::fs;

fn main() {
    fs::create_dir_all("/tmp/testdir").unwrap();
    fs::write("/tmp/testdir/a.txt", "a").unwrap();
    fs::write("/tmp/testdir/b.txt", "b").unwrap();

    let mut entries: Vec<String> = fs::read_dir("/tmp/testdir")
        .unwrap()
        .map(|e| e.unwrap().file_name().into_string().unwrap())
        .collect();
    entries.sort();
    for e in entries { println!("{}", e); }
}
